import type { AudioEffect } from "./BaseEffect.js";

export interface DistortionParams {
  drive: number;
  outputGain: number;
}

export class DistortionEffect implements AudioEffect {
  readonly name = "distortion";

  private _drive: number;
  private _outputGain: number;

  constructor(params?: Partial<DistortionParams>) {
    this._drive = params?.drive ?? 0.5;
    this._outputGain = params?.outputGain ?? 0.7;
  }

  get drive(): number { return this._drive; }
  get outputGain(): number { return this._outputGain; }

  setDrive(v: number): void {
    this._drive = Math.max(0, Math.min(1, v));
  }

  setOutputGain(v: number): void {
    this._outputGain = Math.max(0, Math.min(1, v));
  }

  isActive(): boolean {
    return this._drive > 0;
  }

  process(samples: Float64Array, _channels: number, _frames: number): void {
    if (this._drive <= 0) return;
    const drive = this._drive * 5;
    const gain = this._outputGain;

    for (let i = 0; i < samples.length; i++) {
      const v = samples[i]!;
      samples[i] = Math.tanh(v * drive) * gain;
    }
  }

  reset(): void {
    // no state
  }
}
